import React, { useState, useEffect } from 'react';
import axios from 'axios';

function App() {
  const [students, setStudents] = useState([]);

  useEffect(() => {
    axios.get('http://localhost:3000/students')
      .then(res => setStudents(res.data))
      .catch(err => console.log("Cillad xogta: ", err));
  }, []);

  const markAttendance = async (id, status) => {
    try {
      await axios.post(`http://localhost:3000/attendance/${id}`, { xaadir: status });
      alert(status ? "√ Sax (Jooga)" : "X Qalad (Maqan)");
    } catch (err) {
      alert("Cillad Backend-ka!");
    }
  };

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      <h1 style={{textAlign: 'center'}}>Xaadiriska Ardayda Dugsiga</h1>
      <table border="1" width="100%" style={{ borderCollapse: 'collapse', marginTop: '20px' }}>
        <thead style={{ background: '#2c3e50', color: 'white' }}>
          <tr>
            <th style={{padding: '12px'}}>Magaca Ardayga</th>
            <th>Fasalka</th>
            <th>Xaadiris</th>
          </tr>
        </thead>
        <tbody>
          {students.map(s => (
            <tr key={s._id} style={{textAlign: 'center'}}>
              <td style={{ padding: '10px' }}>{s.magaca}</td>
              <td>{s.fasalka}</td>
              <td>
                <button onClick={() => markAttendance(s._id, true)} style={{ background: 'green', color: 'white', border: 'none', padding: '5px 15px', cursor: 'pointer', borderRadius: '4px' }}>√ Sax</button>
                <button onClick={() => markAttendance(s._id, false)} style={{ background: 'red', color: 'white', border: 'none', padding: '5px 15px', cursor: 'pointer', borderRadius: '4px', marginLeft: '5px' }}>X Qalad</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

export default App;
